# Filter cost data to a specific tag value using Azure CLI
az costmanagement query \
  --scope "/subscriptions/$(az account show --query id -o tsv)" \
  --type Usage \
  --timeframe MonthToDate \
  --dataset-filter '{
    "and": [
      {
        "dimensions": {
          "name": "TagKey",
          "operator": "In",
          "values": ["CostCenter"]
        }
      },
      {
        "tags": {
          "name": "CostCenter",
          "operator": "In",
          "values": ["payments"]
        }
      }
    ]
  }' \
  --dataset-grouping '[{"type":"TagValue","name":"CostCenter"}]' \
  --dataset-granularity None \
  --query 'properties.rows' -o table

# Group by Application tag to see cost per service
az costmanagement query \
  --scope "/subscriptions/$(az account show --query id -o tsv)" \
  --type Usage \
  --timeframe MonthToDate \
  --dataset-grouping '[
    {"type":"TagValue","name":"Application"},
    {"type":"TagValue","name":"Environment"}
  ]' \
  --dataset-granularity None \
  --query 'properties.rows[].{Cost:@[0],Application:@[1],Environment:@[2]}' -o table

# Create a budget scoped to a specific CostCenter tag value
az consumption budget create \
  --budget-name "payments-team-monthly" \
  --scope "/subscriptions/$(az account show --query id -o tsv)" \
  --amount 5000 \
  --time-grain Monthly \
  --start-date "2024-01-01" \
  --end-date "2025-12-31" \
  --category Cost \
  --filters '{
    "tags": {
      "CostCenter": ["payments"]
    }
  }' \
  --notifications '{
    "Actual_80": {
      "enabled": true,
      "operator": "GreaterThan",
      "threshold": 80,
      "contactEmails": ["payments-lead@corp.com"],
      "thresholdType": "Actual"
    },
    "Forecasted_100": {
      "enabled": true,
      "operator": "GreaterThan",
      "threshold": 100,
      "contactEmails": ["platform-finance@corp.com"],
      "thresholdType": "Forecasted"
    }
  }'

# List all budgets and their current spend
az consumption budget list \
  --scope "/subscriptions/$(az account show --query id -o tsv)" \
  --query '[].{
    Name: name,
    Amount: amount,
    CurrentSpend: currentSpend.amount,
    TimeGrain: timeGrain
  }' -o table

# Normalize tag columns across different Cost Management export schema versions
import pandas as pd
import json
from io import BytesIO

def load_export_with_tags(csv_bytes: bytes) -> pd.DataFrame:
    # Load a Cost Management export CSV and normalize tag columns.
    df = pd.read_csv(BytesIO(csv_bytes), low_memory=False)

    # Schema v1: tags_<key> columns (lowercase with underscore prefix)
    v1_tag_cols = [c for c in df.columns if c.lower().startswith('tags_')]
    for col in v1_tag_cols:
        tag_key = col[5:]  # strip 'tags_' prefix
        df[f'tag_{tag_key}'] = df[col]

    # Schema v2: Tags/<key> columns
    v2_tag_cols = [c for c in df.columns if c.startswith('Tags/')]
    for col in v2_tag_cols:
        tag_key = col[5:]  # strip 'Tags/' prefix
        df[f'tag_{tag_key}'] = df[col]

    # Schema v3: single JSON-encoded 'Tags' column
    if 'Tags' in df.columns and not v1_tag_cols and not v2_tag_cols:
        def parse_tags(val):
            if pd.isna(val) or val == '':
                return {}
            try:
                return json.loads(val) if isinstance(val, str) and val.startswith('{') else {}
            except Exception:
                return {}
        tag_dicts = df['Tags'].apply(parse_tags)
        all_keys = set(k for d in tag_dicts for k in d.keys())
        for key in all_keys:
            df[f'tag_{key}'] = tag_dicts.apply(lambda d, k=key: d.get(k, ''))

    return df

# Usage
with open('/mnt/exports/2024-01-01.csv', 'rb') as f:
    df = load_export_with_tags(f.read())

# Tag columns are now consistently named tag_CostCenter, tag_Environment, etc.
print('Tag columns:', [c for c in df.columns if c.startswith('tag_')])
print(df.groupby('tag_CostCenter')['CostInBillingCurrency'].sum().sort_values(ascending=False))

# Create a cost allocation rule to redistribute shared platform costs
# Cost allocation rules can be configured via the REST API:

az rest \
  --method PUT \
  --url 'https://management.azure.com/providers/Microsoft.Management/managementGroups/mg-corp/providers/Microsoft.CostManagement/costAllocationRules/split-platform-costs?api-version=2020-03-01-preview' \
  --body '{
    "properties": {
      "description": "Split platform shared subscription costs to consuming teams",
      "status": "Active",
      "details": {
        "sourceResources": [
          {
            "resourceType": "Dimension",
            "name": "SubscriptionId",
            "values": ["PLATFORM_SUBSCRIPTION_ID"]
          }
        ],
        "targetResources": [
          {
            "resourceType": "Tag",
            "name": "CostCenter",
            "values": [
              { "name": "payments",  "percentage": 40 },
              { "name": "identity",  "percentage": 25 },
              { "name": "data",      "percentage": 20 },
              { "name": "security",  "percentage": 15 }
            ]
          }
        ]
      }
    }
  }'

# Verify the rule is active
az rest \
  --method GET \
  --url 'https://management.azure.com/providers/Microsoft.Management/managementGroups/mg-corp/providers/Microsoft.CostManagement/costAllocationRules?api-version=2020-03-01-preview' \
  --query 'value[].{Name:name,Status:properties.status}' -o table
